import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.C9sp7nFj.js";const _=JSON.parse('{"title":"行李托运规则","description":"国际航班行李托运规定和注意事项","frontmatter":{"title":"行李托运规则","description":"国际航班行李托运规定和注意事项"},"headers":[],"relativePath":"knowledge/flights/baggage.md","filePath":"knowledge/flights/baggage.md","lastUpdated":null}'),l={name:"knowledge/flights/baggage.md"};function i(n,a,d,s,h,c){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="行李托运规则" tabindex="-1">行李托运规则 <a class="header-anchor" href="#行李托运规则" aria-label="Permalink to &quot;行李托运规则&quot;">​</a></h1><h2 id="托运行李规定" tabindex="-1">托运行李规定 <a class="header-anchor" href="#托运行李规定" aria-label="Permalink to &quot;托运行李规定&quot;">​</a></h2><p>大多数国际航班允许托运1-2件行李，每件不超过23公斤。超出部分会产生昂贵的超重费用。</p><h2 id="随身行李规定" tabindex="-1">随身行李规定 <a class="header-anchor" href="#随身行李规定" aria-label="Permalink to &quot;随身行李规定&quot;">​</a></h2><p>随身行李通常限重7-10公斤，尺寸需能放入座位上方的行李架。液体物品需遵守100ml限制规定。</p><h2 id="违禁物品清单" tabindex="-1">违禁物品清单 <a class="header-anchor" href="#违禁物品清单" aria-label="Permalink to &quot;违禁物品清单&quot;">​</a></h2><p>打火机、充电宝（超过规定容量）、刀具等禁止随身携带。具体规定因国家和航空公司而异。</p><h2 id="行李丢失处理" tabindex="-1">行李丢失处理 <a class="header-anchor" href="#行李丢失处理" aria-label="Permalink to &quot;行李丢失处理&quot;">​</a></h2><p>如行李未能到达，立即在机场行李服务台登记并索取行李事故报告单。航空公司通常会负责追踪和赔偿。</p>',9)])])}const g=e(l,[["render",i]]);export{_ as __pageData,g as default};
